import React from 'react';
import { Link } from 'react-router-dom'; // Importa Link para la navegación interna

const Footer = () => {
  return (
    <footer style={styles.footerContainer}>
      <div style={styles.footerContent}>
        {/* Sección 1: Más información */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>más información</h3>
          <ul style={styles.linkListSingle}>
            <li><Link to="/empresas" style={styles.link}>Empresas</Link></li>
            <li><Link to="/historia" style={styles.link}>Nuestra Historia</Link></li>
            <li><a href="#" style={styles.link}>Novedades</a></li>
            <li><Link to="/contacto" style={styles.link}>Contacto</Link></li>
          </ul>
        </div>

        {/* Sección 2: Encuéntranos / Club de Correo / Redes Sociales */}
        <div style={styles.sectionCenter}>
          <h3 style={styles.sectionTitle}>encuéntranos</h3>
          {/* El botón "UBICADOR DE TIENDAS" ahora lleva a "Nuestra Historia" (el equivalente a "nosotros") */}
          <Link to="/historia" style={{ textDecoration: 'none' }}>
            <button style={styles.storeLocatorButton}>ACERCA DE NOSOTROS</button>
          </Link>

          <h3 style={{ ...styles.sectionTitle, marginTop: '20px' }}>club de correo</h3>
          <p style={styles.emailClubText}>Mantente al día con nuestras noticias y ofertas.</p>
          <div style={styles.emailInputContainer}>
            <input type="email" placeholder="tu correo electrónico" style={styles.emailInput} />
            <button style={styles.emailSubmitButton}>&rarr;</button>
          </div>
          <div style={styles.socialIcons}>
            {/* Asegúrate de tener Font Awesome CDN o como paquete npm */}
            <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-facebook-f"></i></a>
            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-instagram"></i></a>
            <a href="https://tiktok.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-tiktok"></i></a>
          </div>
        </div>

        {/* Sección 3: Necesitas ayuda? */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>necesitas ayuda?</h3>
          <ul style={styles.linkListSingle}>
            <li><Link to="/contacto" style={styles.link}>Contacta con nosotros</Link></li>
            <li><Link to="/privacidad" style={styles.link}>Política de Privacidad</Link></li>
            <li><a href="#" style={styles.link}>Términos del servicio</a></li>
            <li><a href="#" style={styles.link}>Preguntas frecuentes</a></li>
          </ul>
        </div>
      </div>

      {/* Sección de créditos "Titulizado por Alberto Navarro" */}
      <div style={styles.creditsBar}>
        <p style={styles.creditsText}>Titulizado por Alberto Navarro</p>
      </div>
    </footer>
  );
};

const styles = {
  footerContainer: {
    backgroundImage: "url('media/footer2.png')", // Ruta relativa a la carpeta 'public'
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundRepeat: 'no-repeat',
    backgroundColor: '#F8F6F1', // Color de fondo de respaldo
    padding: '30px 15px 10px 15px', // Padding más pequeño para un footer más compacto
    color: '#333',
    fontFamily: "'Poppins', sans-serif",
    borderTop: '1px solid #eee',
    boxShadow: '0 -2px 8px rgba(0,0,0,0.03)', // Sombra más sutil
  },
  footerContent: {
    display: 'flex',
    justifyContent: 'space-around',
    flexWrap: 'wrap',
    maxWidth: '760px', // Ancho máximo ligeramente más pequeño
    margin: '0 auto',
    gap: '25px', // Espacio entre columnas
    marginBottom: '15px', // Espacio entre contenido y créditos
  },
  section: {
    flex: '1 1 180px', // Flex-basis más pequeño
    minWidth: '160px',
  },
  sectionCenter: {
    flex: '1 1 280px', // Flex-basis más pequeño
    minWidth: '200px',
    textAlign: 'center',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  sectionTitle: {
    fontSize: '1rem', // Fuente un poco más pequeña
    fontWeight: 'bold',
    marginBottom: '12px', // Margen más pequeño
    textTransform: 'uppercase',
    color: '#333', // Asegurar color de título
  },
  linkListSingle: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
    lineHeight: '1.5', // Espaciado entre elementos de la lista
  },
  link: {
    textDecoration: 'none',
    color: '#555', // Color de enlace un poco más suave
    fontSize: '0.88rem', // Fuente de enlace un poco más pequeña
    transition: 'color 0.3s ease, transform 0.2s ease', // Añadir transición de transform
    display: 'inline-block', // Para que transform funcione bien
    '&:hover': {
      color: '#166D3B', // Color de hover verde
      transform: 'translateX(3px)', // Efecto de desplazamiento sutil al pasar el mouse
    },
  },
  storeLocatorButton: {
    backgroundColor: '#28a745', // Un verde más vibrante
    color: 'white',
    border: 'none',
    padding: '9px 18px', // Padding más pequeño
    borderRadius: '4px', // Borde un poco más suave
    cursor: 'pointer',
    fontSize: '0.8rem', // Fuente más pequeña
    fontWeight: 'bold',
    textTransform: 'uppercase',
    marginTop: '5px',
    letterSpacing: '0.5px', // Espaciado entre letras
    transition: 'background-color 0.3s ease, transform 0.2s ease',
    '&:hover': {
      backgroundColor: '#1e7e34', // Tono más oscuro al hover
      transform: 'scale(1.03)', // Efecto de zoom sutil
    },
    '&:active': {
      transform: 'scale(0.98)', // Efecto de clic
    }
  },
  emailClubText: {
    fontSize: '0.8rem', // Fuente más pequeña
    color: '#666',
    marginBottom: '10px',
    lineHeight: '1.4',
  },
  emailInputContainer: {
    display: 'flex',
    width: '95%',
    maxWidth: '250px', // Ancho máximo más pequeño
    borderBottom: '1px solid #999', // Borde más suave
    paddingBottom: '3px',
    marginBottom: '15px', // Margen más pequeño
    alignItems: 'center', // Centrar verticalmente elementos
  },
  emailInput: {
    flexGrow: 1,
    border: 'none',
    outline: 'none',
    backgroundColor: 'transparent',
    fontSize: '0.85rem', // Fuente más pequeña
    color: '#333',
    padding: '3px 0',
    '&::placeholder': {
      color: '#bbb', // Placeholder más claro
    },
  },
  emailSubmitButton: {
    background: 'none',
    border: 'none',
    fontSize: '1.1rem', // Fuente más pequeña
    color: '#555', // Color más suave
    cursor: 'pointer',
    padding: '3px',
    transition: 'color 0.3s ease, transform 0.2s ease',
    '&:hover': {
      color: '#166D3B',
      transform: 'translateX(3px)', // Efecto de desplazamiento
    },
  },
  socialIcons: {
    display: 'flex',
    gap: '18px', // Espacio entre íconos
    marginTop: '15px',
  },
  socialIcon: {
    color: '#444', // Color de ícono ligeramente más oscuro
    fontSize: '1.6rem', // Tamaño de ícono más pequeño
    transition: 'color 0.3s ease, transform 0.2s ease',
    '&:hover': {
      color: '#166D3B',
      transform: 'scale(1.1)', // Efecto de zoom en íconos
    },
  },
  creditsBar: {
    textAlign: 'center',
    fontSize: '0.75rem', // Fuente de créditos aún más pequeña
    color: '#666', // Color más suave
    paddingTop: '8px', // Padding más pequeño
    borderTop: '1px solid #eee',
    marginTop: 'auto',
  },
  creditsText: {
    margin: 0,
  },
};

export default Footer;
